import React, { useState, useEffect } from "react";

function App() {
  const [apiResponse, test] = useState("");
  const db_info = useState("");


  // function to get the db info
  const call_db = () => {
    fetch("http://localhost:9000/testAPI/user/")
      .then((res) => res.text())
      .then((res) => test(res));
  };

    // Function to call the API
  const callAPI = () => {
    fetch("http://localhost:9000/testAPI")
      .then((res) => res.json())
  };


  // Runs once when the component loads
  useEffect(() => {
    callAPI();
    call_db();
  }, []);

  return (
    <div className="App">
      <h1>Express + React Test</h1>
      <p>{apiResponse}</p>

      <label for="fname">First name : </label>
      <input type="text" name="fname"></input>
      <br></br>
      <label for="fname">Last name : </label>

      <input type="text" name="fname"></input>




    </div>
  );
}

export default App;
